def get_redis_connection() -> redis.StrictRedis:
    """
    Create a secure Redis connection with authentication and TLS.
    Credentials are loaded from environment variables, never hardcoded.
    """
    redis_password = os.environ.get('REDIS_PASSWORD')
    if not redis_password:
        raise RuntimeError(
            "REDIS_PASSWORD environment variable must be set. "
            "Redis must not be used without authentication."
        )

    redis_host = os.environ.get('REDIS_HOST', 'localhost')
    redis_port = int(os.environ.get('REDIS_PORT', '6379'))
    redis_db = int(os.environ.get('REDIS_DB', '0'))
    redis_use_ssl = os.environ.get('REDIS_USE_SSL', 'false').lower() == 'true'

    # Validate host and port
    if not redis_host or not isinstance(redis_port, int) or redis_port < 1 or redis_port > 65535:
        raise ValueError("Invalid Redis host or port configuration")

    connection_kwargs = {
        'host': redis_host,
        'port': redis_port,
        'db': redis_db,
        'password': redis_password,
        'decode_responses': True,
        'socket_timeout': 5,
        'socket_connect_timeout': 5,
        'retry_on_timeout': True,
        'health_check_interval': 30,
    }

    if redis_use_ssl:
        redis_ca_cert = os.environ.get('REDIS_CA_CERT_PATH')
        connection_kwargs['ssl'] = True
        connection_kwargs['ssl_cert_reqs'] = 'required'
        if redis_ca_cert:
            connection_kwargs['ssl_ca_certs'] = redis_ca_cert

    pool = redis.ConnectionPool(**connection_kwargs)
    client = redis.StrictRedis(connection_pool=pool)

    # Verify connection and authentication
    try:
        client.ping()
        logger.info("Successfully connected to Redis with authentication")
    except redis.AuthenticationError:
        logger.error("Redis authentication failed - check REDIS_PASSWORD")
        raise
    except redis.ConnectionError as e:
        logger.error("Failed to connect to Redis: %s", type(e).__name__)
        raise

    return client


