# --- Secure Caching Decorator ---

class RedisCache:
    """
    Secure Redis-based cache with key namespacing and input validation.
    """

    CACHE_PREFIX = "cache:"
    MAX_KEY_LENGTH = 256
    MAX_VALUE_SIZE = 1048576  # 1MB

    def __init__(self, redis_client: redis.StrictRedis, default_ttl: int = 300):
        self.redis = redis_client
        self.default_ttl = default_ttl

    def _make_cache_key(self, func_name: str, args: tuple, kwargs: dict) -> str:
        """
        Generate a safe, deterministic cache key from function arguments.
        Uses hashing to prevent key injection and ensure fixed-length keys.
        """
        # Create a canonical representation of the arguments
        key_data = json.dumps({
            'func': func_name,
            'args': [str(a) for a in args],
            'kwargs': {str(k): str(v) for k, v in sorted(kwargs.items())}
        }, sort_keys=True)

        key_hash = hashlib.sha256(key_data.encode('utf-8')).hexdigest()
        return f"{self.CACHE_PREFIX}{func_name}:{key_hash}"

    def cached(self, ttl: Optional[int] = None, key_prefix: Optional[str] = None) -> Callable:
        """
        Decorator to cache function results in Redis.

        Args:
            ttl: Time-to-live in seconds (defaults to default_ttl)
            key_prefix: Optional prefix for cache keys
        """
        cache_ttl = ttl if ttl is not None else self.default_ttl

        def decorator(func: Callable) -> Callable:
            @functools.wraps(func)
            def wrapper(*args, **kwargs) -> Any:
                func_name = key_prefix or func.__qualname__

                cache_key = self._make_cache_key(func_name, args, kwargs)

                if len(cache_key) > self.MAX_KEY_LENGTH:
                    logger.warning("Cache key too long, skipping cache for %s", func_name)
                    return func(*args, **kwargs)

                try:
                    cached_value = self.redis.get(cache_key)
                    if cached_value is not None:
                        result = json.loads(cached_value)
                        logger.debug("Cache hit for %s", func_name)
                        return result
                except (redis.RedisError, json.JSONDecodeError) as e:
                    logger.warning("Cache read error for %s: %s", func_name, type(e).__name__)

                # Cache miss - execute function
                result = func(*args, **kwargs)

                try:
                    serialized = json.dumps(result)
                    if len(serialized) > self.MAX_VALUE_SIZE:
                        logger.warning("Cache value too large for %s, skipping cache", func_name)
                        return result

                    self.redis.setex(cache_key, cache_ttl, serialized)
                    logger.debug("Cached result for %s with TTL %d", func_name, cache_ttl)
                except (redis.RedisError, TypeError) as e:
                    logger.warning("Cache write error for %s: %s", func_name, type(e).__name__)

                return result

            # Add cache invalidation method
            def invalidate(*args, **kwargs):
                func_name = key_prefix or func.__qualname__
                cache_key = self._make_cache_key(func_name, args, kwargs)
                try:
                    self.redis.delete(cache_key)
                    logger.info("Invalidated cache for %s", func_name)
                except redis.RedisError as e:
                    logger.warning("Cache invalidation error: %s", type(e).__name__)

            wrapper.invalidate = invalidate
            return wrapper

        return decorator

    def invalidate_pattern(self, pattern: str) -> int:
        """
        Invalidate cache entries matching a pattern.
        Only allows patterns within the cache namespace.
        """
        # Validate pattern - must start with cache prefix
        if not pattern.startswith(self.CACHE_PREFIX):
            pattern = f"{self.CACHE_PREFIX}{pattern}"

        # Prevent dangerous patterns
        if pattern in ('*', '**', self.CACHE_PREFIX + '*'):
            logger.warning("Overly broad cache invalidation pattern rejected")
            return 0

        count = 0
        try:
            cursor = 0
            while True:
                cursor, keys = self.redis.scan(cursor, match=pattern, count=100)
                if keys:
                    # Only delete keys within our namespace
                    safe_keys = [k for k in keys if k.startswith(self.CACHE_PREFIX)]
                    if safe_keys:
                        count += self.redis.delete(*safe_keys)
                if cursor == 0:
                    break
        except redis.RedisError as e:
            logger.warning("Pattern invalidation error: %s", type(e).__name__)

        return count


# --- Rate Limiting ---

class RateLimiter:
    """Simple Redis-based rate limiter."""

    RATE_LIMIT_PREFIX = "ratelimit:"

    def __init__(self, redis_client: redis.StrictRedis, max_requests: int = 100,
                 window_seconds: int = 60):
        self.redis = redis_client
        self.max_requests = max_requests
        self.window_seconds = window_seconds

    def is_rate_limited(self, identifier: str) -> bool:
        """Check if the identifier has exceeded the rate limit."""
        # Hash the identifier to prevent key injection
        safe_id = hashlib.sha256(identifier.encode('utf-8')).hexdigest()[:32]
        key = f"{self.RATE_LIMIT_PREFIX}{safe_id}"

        try:
            pipe = self.redis.pipeline(transaction=True)
            now = time.time()
            window_start = now - self.window_seconds

            pipe.zremrangebyscore(key, 0, window_start)
            pipe.zadd(key, {str(now): now})
            pipe.zcard(key)
            pipe.expire(key, self.window_seconds)

            results = pipe.execute()
            request_count = results[2]

            return request_count > self.max_requests
        except redis.RedisError as e:
            logger.error("Rate limiter error: %s", type(e).__name__)
            # Fail open but log - adjust based on security requirements
            return False


# --- Input Validation ---

def sanitize_string(value: str, max_length: int = 255, allow_chars: str = '') -> str:
    """Sanitize a string input."""
    if not isinstance(value, str):
        raise ValueError("Expected string input")
    # Truncate to max length
    value = value[:max_length]
    # Remove null bytes and control characters
    value = ''.join(c for c in value if c.isprintable() or c in allow_chars)
    return value.strip()


def validate_username(username: str) -> str:
    """Validate and sanitize a username."""
    if not username or not isinstance(username, str):
        raise ValueError("Username is required")
    username = sanitize_string(username, max_length=64)
    if len(username) < 3:
        raise ValueError("Username must be at least 3 characters")
    # Allow only alphanumeric, underscore, hyphen
    if not all(c.isalnum() or c in '_-' for c in username):
        raise ValueError("Username contains invalid characters")
    return username


